import java.util.*; public class StudentManagementSystem{static ArrayList<Student> l=new ArrayList<>();public static void run(){Scanner s=new Scanner(System.in);while(true){System.out.println("1.Add 2.View 3.Exit");int c=s.nextInt();if(c==1){System.out.print("Id:");int i=s.nextInt();System.out.print("Name:");String n=s.next();l.add(new Student(i,n));}else if(c==2){for(Student st:l)System.out.println(st.id+" "+st.name);}else break;}}}